-- ============================================================
-- 10. announcement（公告通知）
-- ============================================================
INSERT IGNORE INTO announcement (id, title, content, announcement_type, status, publisher_id, published_at, created_at, updated_at) VALUES
(1, '春节期间停车优惠活动',
    '尊敬的车主朋友们：\n\n为迎接2026年春节，本停车场于1月25日至2月10日期间推出停车优惠活动：\n1. 普通车位8折优惠\n2. VIP车位7折优惠\n3. 充电桩免服务费\n\n预祝各位新春快乐，万事如意！\n\n智能停车场管理处',
    'PROMOTION', 1, 1, '2026-01-20 09:00:00', '2026-01-18 14:00:00', '2026-01-20 09:00:00'),

(2, '地下车库维修通知',
    '各位车主：\n\nC区（地下二层）将于2026年2月15日至2月17日进行照明系统升级和消防管道检修，届时C区将暂停使用。请将车辆停放至其他区域。\n\n给您带来不便，敬请谅解。\n\n智能停车场管理处',
    'MAINTENANCE', 1, 1, '2026-02-01 10:00:00', '2026-01-28 16:00:00', '2026-02-01 10:00:00'),

(3, '新增VIP车位服务',
    '亲爱的车主：\n\n为提升停车体验，D区VIP专区现已全面升级：\n1. 独立出入口，专用通道\n2. 24小时专人值守\n3. 免费洗车服务（每月2次）\n4. 优先预约权\n\n欢迎致电0371-12345678咨询详情。\n\n智能停车场管理处',
    'NOTICE', 1, 1, '2025-12-01 08:00:00', '2025-11-28 10:00:00', '2025-12-01 08:00:00'),

(4, '系统升级公告',
    '尊敬的用户：\n\n智能停车场管理系统将于2026年2月20日凌晨2:00-5:00进行系统升级维护，届时APP和微信小程序将暂时无法使用，道闸系统正常运行。\n\n升级内容：\n1. 新增车位实时导航功能\n2. 优化支付流程\n3. 新增月卡/季卡功能\n\n感谢您的理解与支持。\n\n智能停车场管理处',
    'NOTICE', 1, 1, '2026-02-05 09:00:00', '2026-02-03 11:00:00', '2026-02-05 09:00:00'),

(5, '安全驾驶温馨提示',
    '各位车主朋友：\n\n为确保停车场内行车安全，请注意以下事项：\n1. 场内限速5km/h\n2. 请按指示标线行驶，禁止逆行\n3. 转弯处请减速慢行，注意行人\n4. 请勿在车位内长时间鸣笛\n5. 发现异常情况请及时联系管理处\n\n安全出行，人人有责。\n\n智能停车场管理处',
    'NOTICE', 1, 1, '2025-11-10 08:00:00', '2025-11-08 14:00:00', '2025-11-10 08:00:00'),

(6, '元旦假期运营安排',
    '各位车主：\n\n2026年元旦假期（1月1日-1月3日）停车场正常运营，营业时间为全天24小时。\n假期期间车流量较大，建议错峰出行。\n\n祝大家元旦快乐！\n\n智能停车场管理处',
    'NOTICE', 1, 1, '2025-12-28 09:00:00', '2025-12-26 10:00:00', '2025-12-28 09:00:00'),

(7, '停车场新增电动车充电桩',
    '尊敬的新能源车主：\n\nE区新增10个120kW直流快充桩，充电30分钟即可补能80%。同时原有慢充桩已全部升级至7kW交流桩。\n\n欢迎使用！\n\n智能停车场管理处',
    'NOTICE', 0, 1, '2026-02-08 08:00:00', '2026-02-06 15:00:00', '2026-02-08 08:00:00'),

(8, '三月停车优惠月活动',
    '尊敬的车主朋友们：\n\n为感谢各位长期以来的支持，本停车场于3月1日至3月31日推出「停车优惠月」活动：\n1. 工作日全场9折优惠\n2. 周末充电桩免服务费\n3. 连续停车超过4小时赠送1小时免费时长\n4. 新用户首次停车立减5元\n\n活动期间，欢迎广大车主体验我们的智能停车服务！\n\n智能停车场管理处',
    'PROMOTION', 1, 1, '2026-03-01 08:00:00', '2026-02-27 14:00:00', '2026-03-01 08:00:00'),

(9, 'A区路面修缮通知',
    '各位车主：\n\nA区（地上停车场）将于2026年3月22日至3月24日进行路面修缮和标线重绘工作，届时A区将暂停使用。\n请将车辆停放至B区、C区或其他可用区域。\n\n修缮完成后，A区将焕然一新，为您提供更好的停车体验。\n\n给您带来不便，敬请谅解。\n\n智能停车场管理处',
    'MAINTENANCE', 1, 1, '2026-03-15 09:00:00', '2026-03-13 16:00:00', '2026-03-15 09:00:00');

