-- 11. review（用户评价）
-- ============================================================
INSERT IGNORE INTO review (id, user_id, order_id, rating, content, reply, reply_at, created_at, updated_at) VALUES
(1,  4,  1,  5, '停车场环境很好，车位宽敞，进出方便，支付也很快捷，非常满意！', '感谢您的好评，我们会继续努力提升服务质量！', '2025-11-11 09:00:00', '2025-11-10 12:00:00', '2025-11-11 09:00:00'),
(2,  5,  2,  4, '地下一层光线不错，就是通风可以再好一些，整体还是满意的。', '感谢您的建议，我们已安排检修通风系统。', '2025-11-13 10:00:00', '2025-11-12 17:30:00', '2025-11-13 10:00:00'),
(3,  6,  3,  5, 'VIP车位真的很值，专用通道不用排队，停车体验一流！', NULL, NULL, '2025-11-15 13:00:00', '2025-11-15 13:00:00'),
(4,  8,  4,  3, '免费时间太短了，才15分钟，有时候办个事都来不及。希望能延长到30分钟。', '感谢反馈，我们会将您的建议提交管理层讨论。', '2025-11-21 14:00:00', '2025-11-20 10:00:00', '2025-11-21 14:00:00'),
(5,  10, 7,  4, '停车位很好找，有实时导航指引，科技感满满。就是高峰期出场有点慢。', '感谢您的评价，高峰期我们会增派人手疏导。', '2025-11-29 09:30:00', '2025-11-28 18:00:00', '2025-11-29 09:30:00'),
(6,  9,  8,  2, '停了两个半小时收了12.5，觉得有点贵。而且缴费的时候等了好久。', '非常抱歉给您带来不好的体验，我们会优化缴费流程。', '2025-12-02 10:00:00', '2025-12-01 11:30:00', '2025-12-02 10:00:00'),
(7,  12, 10, 5, '充电桩区域很方便，一边充电一边停车，充电速度也很快！', NULL, NULL, '2025-12-12 15:00:00', '2025-12-12 15:00:00'),
(8,  13, 11, 4, '整体不错，就是地下二层信号不太好，希望能加强一下。', '收到，我们正在规划安装信号增强器。', '2025-12-16 11:00:00', '2025-12-15 10:30:00', '2025-12-16 11:00:00'),
(9,  7,  16, 5, '充电桩区体验极佳，新增的快充桩速度很快，半小时就充满了。强烈推荐！', NULL, NULL, '2025-12-20 17:00:00', '2025-12-20 17:00:00'),
(10, 4,  20, 4, '春节优惠活动很给力，VIP车位打七折非常划算。希望以后多搞活动！', '感谢支持，后续我们会推出更多优惠活动。', '2026-01-06 10:00:00', '2026-01-05 14:00:00', '2026-01-06 10:00:00'),
(11, 6,  21, 1, '这次停车体验很差，VIP车位居然被别人占了，管理员也没及时处理。', '非常抱歉，我们已加强VIP区域的巡查管理，确保不再出现此类问题。', '2026-01-09 09:00:00', '2026-01-08 13:00:00', '2026-01-09 09:00:00'),
(12, 15, 18, 5, '充电桩的充电速度很快，停车环境也很干净整洁，下次还来！', NULL, NULL, '2025-12-23 12:00:00', '2025-12-23 12:00:00'),
-- 2026年3月评价
(13, 4,  35, 5, '三月优惠活动太给力了！工作日九折，加上连续停车赠送免费时长，非常划算。停车场环境也越来越好了。', '感谢您的好评！活动期间欢迎多多使用我们的服务。', '2026-03-02 09:00:00', '2026-03-01 13:00:00', '2026-03-02 09:00:00'),
(14, 7,  38, 4, '充电桩区域非常方便，一边充电一边办事。就是高峰期快充桩有时候要排队等，希望能再多加几个。', '感谢您的建议，我们正在规划扩建快充桩。', '2026-03-06 10:00:00', '2026-03-05 16:00:00', '2026-03-06 10:00:00'),
(15, 5,  36, 5, '地下一层的通风系统升级后明显好多了，空气流通很好，灯光明亮。预约系统也很好用，到了就有位停。', NULL, NULL, '2026-03-02 12:00:00', '2026-03-02 12:00:00'),
(16, 13, 46, 3, '停车场整体不错，但是出场时扫码支付等了一会儿才成功，可能是网络信号不太好。建议优化一下支付流程。', '收到您的反馈，我们正在优化支付系统的稳定性。', '2026-03-19 11:00:00', '2026-03-18 11:00:00', '2026-03-19 11:00:00');

